
.status-shell {
  --line: #1f2933;
  --text: #11202c;
  --panel: #f8f7f3;
  --accent: #ef7d57;
  --accent-soft: #f7b267;
  width: 100%;
  max-width: 430px;
  margin: 0 auto;
  padding: 10px 0;
  font-family: 'Source Han Sans SC', 'PingFang SC', 'Microsoft YaHei', sans-serif;
}

.phone-frame {
  width: 100%;
  aspect-ratio: 9 / 19;
  border: 4px solid var(--line);
  border-radius: 38px;
  background:
    radial-gradient(circle at 90% 8%, #ffd89f 0%, transparent 38%),
    radial-gradient(circle at 10% 22%, #9ad1d4 0%, transparent 35%),
    linear-gradient(165deg, #f6f1e8 0%, #f8f7f3 44%, #eef2f7 100%);
  box-shadow:
    0 18px 34px rgba(16, 24, 32, 0.2),
    inset 0 0 0 2px rgba(255, 255, 255, 0.9);
  padding: 14px 14px 12px;
  display: flex;
  flex-direction: column;
  gap: 10px;
  position: relative;
  color: var(--text);
}

.phone-notch {
  width: 42%;
  height: 22px;
  border-radius: 0 0 16px 16px;
  background: var(--line);
  margin: 0 auto;
}

.top-bar {
  display: flex;
  justify-content: space-between;
  font-size: 11px;
  opacity: 0.85;
}

.profile-card {
  background: rgba(255, 255, 255, 0.76);
  border: 1px solid rgba(17, 32, 44, 0.2);
  border-radius: 18px;
  padding: 10px;
  display: flex;
  align-items: center;
  gap: 10px;
}

.avatar {
  width: 44px;
  aspect-ratio: 1;
  border-radius: 14px;
  background: linear-gradient(135deg, var(--accent) 0%, var(--accent-soft) 100%);
  color: #fff;
  font-weight: 700;
  display: grid;
  place-items: center;
  font-size: 20px;
}

.identity {
  display: grid;
  gap: 2px;
}

.name {
  margin: 0;
  font-size: 16px;
  font-weight: 700;
}

.meta,
.mood {
  margin: 0;
  font-size: 12px;
}

.status-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 8px;
}

.status-item {
  background: var(--panel);
  border: 1px solid rgba(17, 32, 44, 0.16);
  border-radius: 14px;
  padding: 8px 9px;
}

.label {
  margin: 0;
  font-size: 11px;
  opacity: 0.78;
}

.value {
  margin: 2px 0 5px;
  font-size: 16px;
  font-weight: 700;
}

.bar {
  height: 5px;
  border-radius: 99px;
  overflow: hidden;
  background: #dee7ee;
}

.bar span {
  display: block;
  height: 100%;
  background: linear-gradient(90deg, var(--accent), var(--accent-soft));
  transition: width 0.35s ease;
}

.chat-card {
  flex: 1;
  background: rgba(255, 255, 255, 0.78);
  border: 1px solid rgba(17, 32, 44, 0.16);
  border-radius: 18px;
  padding: 10px;
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.chat-title {
  margin: 0;
  font-size: 12px;
  font-weight: 700;
}

.bubble-list {
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.bubble-row {
  display: flex;
  flex-direction: column;
  gap: 2px;
  align-items: flex-start;
}

.bubble-row.user {
  align-items: flex-end;
}

.sender {
  font-size: 10px;
  opacity: 0.75;
}

.bubble {
  margin: 0;
  padding: 6px 10px;
  max-width: 90%;
  border-radius: 12px 12px 12px 4px;
  background: #eff5fb;
  font-size: 12px;
  line-height: 1.35;
}

.bubble-row.user .bubble {
  border-radius: 12px 12px 4px 12px;
  background: #ffe3c7;
}
